  const printQrCode = (qr: any) => {
    const iframe = document.createElement('iframe');
    iframe.style.position = 'fixed';
    iframe.style.right = '0';
    iframe.style.bottom = '0';
    iframe.style.width = '0';
    iframe.style.height = '0';
    iframe.style.border = '0';
    document.body.appendChild(iframe);

    const doc = iframe.contentWindow?.document;
    if (doc) {
      doc.open();
      doc.write(`
        <html>
          <head>
            <title>Print QR Code - ${qr.label}</title>
            <style>
              @media print {
                body { margin: 0; padding: 0; }
                @page { size: auto; margin: 0; }
              }
              body {
                font-family: 'Inter', system-ui, -apple-system, sans-serif;
                display: flex;
                flex-direction: column;
                align-items: center;
                justify-content: center;
                padding: 20px;
                text-align: center;
                background: #ffffff;
                color: #000000;
                width: 280px;
                margin: 0 auto;
              }
              .header {
                font-weight: 900;
                font-size: 14px;
                text-transform: uppercase;
                letter-spacing: 2px;
                margin-bottom: 4px;
                border-bottom: 2px solid #000;
                width: 100%;
                padding-bottom: 4px;
              }
              .sub-header {
                font-size: 9px;
                font-weight: 700;
                text-transform: uppercase;
                letter-spacing: 1px;
                margin-bottom: 15px;
                opacity: 0.7;
              }
              .qr-container {
                border: 1px solid #ddd;
                padding: 8px;
                margin-bottom: 15px;
                background: #fff;
              }
              .qr-image {
                width: 180px;
                height: 180px;
                display: block;
              }
              .meta {
                width: 100%;
                border-top: 1px dashed #000;
                padding-top: 10px;
                margin-top: 10px;
              }
              .label {
                font-size: 13px;
                font-weight: 800;
                text-transform: uppercase;
                margin-bottom: 2px;
              }
              .details {
                font-size: 10px;
                font-family: monospace;
                letter-spacing: 0.5px;
                margin-bottom: 5px;
              }
              .slug {
                font-size: 8px;
                text-transform: uppercase;
                letter-spacing: 1px;
                opacity: 0.5;
              }
            </style>
          </head>
          <body onload="window.print(); setTimeout(() => { window.frameElement.remove(); }, 500)">
            <div class="header">SMOKE EATERS</div>
            <div class="sub-header">OPERATIONS PORTAL</div>
            <div class="qr-container">
              <img class="qr-image" src="${qr.qrDataUrl}" />
            </div>
            <div class="meta">
              <div class="label">${qr.label}</div>
              <div class="details">${qr.type.toUpperCase()}: ${qr.identifier} ${qr.secondaryId ? `| SEAT: ${qr.secondaryId}` : ''}</div>
              <div class="slug">Scan to Connect • Pro Dashboard</div>
            </div>
          </body>
        </html>
      `);
      doc.close();
    }
  };

