    if (duration > 0) {
      const updatedTime = new Date(employeeAlert.updatedAt).getTime();
      const expiresTime = updatedTime + (duration * 24 * 60 * 60 * 1000);
      if (Date.now() > expiresTime) {
        return false;
      }
    }

    // Check if audience is 'next' and it has already been acknowledged by any employee
    const audienceType = employeeAlert.audience ?? 'all';
    if (audienceType === 'next') {
      const isAlreadyAcknowledged = Object.values(acknowledgedAlerts).some(list => 
        (list || []).includes(employeeAlert.id)
      );
      if (isAlreadyAcknowledged) {
        return false;
      }
    }

    return true;
