  useEffect(() => {
    if (!inventory) return;
    
    const timeoutId = setTimeout(() => {
      const newAlerts: {m: string, t: StaffNotification['t'], p?: boolean}[] = [];
      const emailAlerts: {item: string, type: 'manual' | 'automatic', level: number}[] = [];
      
      Object.entries(inventory).forEach(([dist, items]) => {
        items.forEach(item => {
          const cur = stock[item.n] || 0;
          const isBelowMin = cur < item.m;
          const isManualLow = !!item.f;
          const isGooseRiver = item.n.toLowerCase().includes('goose river') || item.n.toLowerCase() === 'goose river bank';

          if (isBelowMin || isManualLow) {
            emailAlerts.push({ item: item.n, type: isManualLow ? 'manual' : 'automatic', level: cur });
            
            if (isGooseRiver) {
              newAlerts.push({ m: `Goose River Bank is low: ${cur} ${item.u || 'item'}`, t: 'alert', p: true });
            } else if (isManualLow) {
              newAlerts.push({ m: `Low Stock Flag: ${item.n}`, t: 'stock' });
            } else {
              newAlerts.push({ m: `Low Stock: ${item.n} (${cur})`, t: 'stock' });
            }
          }
        });
      });

      if (emailAlerts.length > 0) {
        sendBatchEmailAlerts(emailAlerts);
      }

      if (newAlerts.length > 0) {
        setNotifications(prev => {
          let updated = [...prev];
          let hasNew = false;
          newAlerts.forEach(alert => {
            const isDuplicate = updated.some(n => n.m === alert.m && (Date.now() - new Date(n.ts).getTime() < 5 * 60 * 1000));
            if (!isDuplicate) {
              updated = [{
                id: Math.random().toString(36).substring(2, 9),
                t: alert.t,
                m: alert.m,
                ts: new Date().toISOString(),
                r: false,
                persistent: alert.p
              }, ...updated];
              hasNew = true;
            }
          });
          return hasNew ? updated.slice(0, 50) : prev;
        });
      }
    }, 5000); // 5 second debounce to avoid rapid alerts while typing

    return () => clearTimeout(timeoutId);
  }, [stock, inventory]);


