  const findInventoryMatch = (scannedName: string, items: string[] | InventoryItem[]): string | null => {
    if (!scannedName) return null;
    const names = items.length > 0 && typeof items[0] === 'string' ? (items as string[]) : (items as InventoryItem[]).map(i => i.n);
    const normScanned = scannedName.toLowerCase().trim().replace(/[^a-z0-9]/g, '');
    
    // 1. Exact match
    const exactMatch = names.find(n => n.toLowerCase().trim() === scannedName.toLowerCase().trim());
    if (exactMatch) return exactMatch;
    
    // 2. Normalized Exact Match
    const normMatch = names.find(n => n.toLowerCase().replace(/[^a-z0-9]/g, '') === normScanned);
    if (normMatch) return normMatch;
    
    // 3. Heuristic: Scanned contains item or item contains scanned
    const sortedNames = [...names].sort((a, b) => b.length - a.length);
    const fuzzyMatch = sortedNames.find(n => {
      const normN = n.toLowerCase().replace(/[^a-z0-9]/g, '');
      return normScanned.includes(normN) || normN.includes(normScanned);
    });
    
    return fuzzyMatch || null;
  };
