  const onFirestoreError = (error: unknown, operationType: OperationType, path: string | null) => {
    const errMessage = error instanceof Error ? error.message : String(error);
    const lowMessage = errMessage.toLowerCase();
    
    // Check for Not Found
    const isNotFound = lowMessage.includes('not-found') || lowMessage.includes('not_found') || lowMessage.includes('code=5');
    if (isNotFound) {
      console.error("[FIREBASE] Database configuration mismatch or document not found.");
      addNotification("Database Sync Error: Configuration mismatch. Please refresh or contact support.", "alert");
    }

    // Check for quota issues
    const isQuota = lowMessage.includes('quota') || lowMessage.includes('exhausted');
    if (isQuota && !quotaExceeded) {
      setQuotaExceeded(true);
      addNotification("Cloud Storage Quota Exceeded. Daily limits are reached; writes are temporarily disabled.", "alert");
    }

    // Call the global handler (renamed to handleGlobalFirestoreError)
    handleGlobalFirestoreError(error, operationType, path);
    
    // Explicitly set quota state if it happens
    if (isQuota) {
      setQuotaExceeded(true);
      addNotification("Firestore Free Tier Quota Exceeded. Database sync paused until tomorrow.", "alert");
    }

    // Notify user of errors unless it's just an offline warning handled elsewhere
    if (!lowMessage.includes('offline') && !isQuota && !isNotFound) {
      addNotification(`Database Error: ${errMessage.substring(0, 50)}...`, "alert");
    }
  };

  // Firebase Auth Listener
  useEffect(() => {
    const unsub = onAuthStateChanged(auth, (u) => {
      setUser(u);
    });
    return () => unsub();
  }, []);

  // Firebase Table Alerts (Call Bartender & Orders) sync list
  useEffect(() => {
    const q = query(collection(db, 'table_alerts'));
    const unsub = onSnapshot(q, (snapshot) => {
      const alertsList: TableAlert[] = [];
      snapshot.forEach((docSnap) => {
        alertsList.push({ id: docSnap.id, ...docSnap.data() } as TableAlert);
      });
      
      // Sort: active first, then date descending
      alertsList.sort((a, b) => {
        if (a.status === 'active' && b.status !== 'active') return -1;
        if (a.status !== 'active' && b.status === 'active') return 1;
        return new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime();
      });

      setTableAlerts(prev => {
        const prevActiveIds = new Set(prev.filter(x => x.status === 'active').map(x => x.id));
        const hasNewActive = alertsList.some(x => x.status === 'active' && !prevActiveIds.has(x.id));
        
        if (hasNewActive && !isPatronMode && currentEmployee) {
          // Play a friendly synth beep/alert audio to grab the bartender's attention
          try {
            const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
            const oscillator = audioCtx.createOscillator();
            const gainNode = audioCtx.createGain();
            
            oscillator.type = 'sine';
            oscillator.frequency.setValueAtTime(880, audioCtx.currentTime); // A5 note
            gainNode.gain.setValueAtTime(0.12, audioCtx.currentTime);
            
            oscillator.connect(gainNode);
            gainNode.connect(audioCtx.destination);
            
            oscillator.start();
            setTimeout(() => {
              oscillator.stop();
              audioCtx.close();
            }, 180);
          } catch (e) {
            console.log("Audio alert playback missed:", e);
          }
        }
        return alertsList;
      });
    }, (error) => {
      console.error("Error syncing table_alerts: ", error);
    });

    return () => unsub();
  }, [isPatronMode, currentEmployee]);

  // Firebase Real-time Sync Listener
  useEffect(() => {
    if (!user && !isPatronMode) return;

    const path = 'system/state';
    const unsub = onSnapshot(doc(db, path), (snapshot) => {
      if (snapshot.exists()) {
        const snapshotMetadata = snapshot.metadata;
        const rawData = snapshot.data();
        
        // Handle migration: if payload is present, use it, otherwise use raw data
        const data = rawData.payload ? JSON.parse(rawData.payload) : rawData;
        const dataClean = sanitizeForFirestore(data);
        const dataString = JSON.stringify(dataClean);
        
        const serverUpdatedAt = rawData.updatedAt ? new Date(rawData.updatedAt).getTime() : 0;
        const localUpdatedAt = lastLocalUpdateRef.current;

        if (dataString === lastSyncHashRef.current) {
          return;
        }

        // Avoid overwriting newer local work with an older server snapshot
        // This is critical when Firestore quota is exhausted or offline
        if (localUpdatedAt > serverUpdatedAt) {
          console.log("[SYNC] Skipping server update: Local state is newer than server state.");
          return;
        }

        isRemoteUpdateRef.current = true;
        lastSyncHashRef.current = dataString;
        
        if (data.tasks) setTasks(prev => JSON.stringify(prev) === JSON.stringify(data.tasks) ? prev : data.tasks);
        if (data.checks) setChecks(prev => JSON.stringify(prev) === JSON.stringify(data.checks) ? prev : data.checks);
        if (data.inventory) setInventory(prev => JSON.stringify(prev) === JSON.stringify(data.inventory) ? prev : data.inventory);
        if (data.stock) setStock(prev => JSON.stringify(prev) === JSON.stringify(data.stock) ? prev : data.stock);
        if (data.posStock) setPosStock(prev => JSON.stringify(prev) === JSON.stringify(data.posStock) ? prev : data.posStock);
        if (data.tills) setTills(prev => JSON.stringify(prev) === JSON.stringify(data.tills) ? prev : data.tills);
        if (data.gaming) setGaming(prev => JSON.stringify(prev) === JSON.stringify(data.gaming) ? prev : data.gaming);
        if (data.invLogs) setInvLogs(prev => JSON.stringify(prev) === JSON.stringify(data.invLogs) ? prev : data.invLogs);
        if (data.taskLogs) setTaskLogs(prev => JSON.stringify(prev) === JSON.stringify(data.taskLogs) ? prev : data.taskLogs);
        if (data.staffLogs) setStaffLogs(prev => JSON.stringify(prev) === JSON.stringify(data.staffLogs) ? prev : data.staffLogs);
        if (data.orderLogs) setOrderLogs(prev => JSON.stringify(prev) === JSON.stringify(data.orderLogs) ? prev : data.orderLogs);
        if (data.helpContent) setHelpContent(prev => JSON.stringify(prev) === JSON.stringify(data.helpContent) ? prev : data.helpContent);
        if (data.distributorMetadata) setDistMetadata(prev => JSON.stringify(prev) === JSON.stringify(data.distributorMetadata) ? prev : data.distributorMetadata);
        if (data.employees) setEmployees(prev => JSON.stringify(prev) === JSON.stringify(data.employees) ? prev : data.employees);
        if (data.recipes) setRecipes(prev => JSON.stringify(prev) === JSON.stringify(data.recipes) ? prev : data.recipes);
        if (data.notifications) setNotifications(prev => JSON.stringify(prev) === JSON.stringify(data.notifications) ? prev : data.notifications);
        if (data.messages) setMessages(prev => JSON.stringify(prev) === JSON.stringify(data.messages) ? prev : data.messages);
        if (data.calendarEvents) setCalendarEvents(prev => JSON.stringify(prev) === JSON.stringify(data.calendarEvents) ? prev : data.calendarEvents);
        if (data.posConfig) setPosConfig(prev => JSON.stringify(prev) === JSON.stringify(data.posConfig) ? prev : data.posConfig);
        if (data.lastPosSync) setLastPosSync(prev => JSON.stringify(prev) === JSON.stringify(data.lastPosSync) ? prev : data.lastPosSync);
        if (data.posLogs) setPosLogs(prev => JSON.stringify(prev) === JSON.stringify(data.posLogs) ? prev : data.posLogs);
        if (data.pinResetRequests) setPinResetRequests(prev => JSON.stringify(prev) === JSON.stringify(data.pinResetRequests) ? prev : data.pinResetRequests);
        if (data.undepositedTotal !== undefined) setUndepositedTotal(prev => prev === data.undepositedTotal ? prev : data.undepositedTotal);
        if (data.categoryColors) setCategoryColors(prev => JSON.stringify(prev) === JSON.stringify(data.categoryColors) ? prev : data.categoryColors);
        if (data.defaultReminderOffset !== undefined) setDefaultReminderOffset(prev => prev === data.defaultReminderOffset ? prev : data.defaultReminderOffset);
        if (data.pricingConfig) setPricingConfig(prev => JSON.stringify(prev) === JSON.stringify(data.pricingConfig) ? prev : data.pricingConfig);
        if (data.brandingConfig) setBrandingConfig(prev => JSON.stringify(prev) === JSON.stringify(data.brandingConfig) ? prev : data.brandingConfig);
        if (data.randomTasksConfig) setRandomTasksConfig(prev => JSON.stringify(prev) === JSON.stringify(data.randomTasksConfig) ? prev : data.randomTasksConfig);
        if (data.commonTitles) setCommonTitles(prev => JSON.stringify(prev) === JSON.stringify(data.commonTitles) ? prev : data.commonTitles);
        if (data.commonLocations) setCommonLocations(prev => JSON.stringify(prev) === JSON.stringify(data.commonLocations) ? prev : data.commonLocations);
        if (data.specials) setSpecials(prev => JSON.stringify(prev) === JSON.stringify(data.specials) ? prev : data.specials);
        if (data.scannedInvoices) setScannedInvoices(prev => JSON.stringify(prev) === JSON.stringify(data.scannedInvoices) ? prev : data.scannedInvoices);

        setLastSync(new Date().toLocaleTimeString());
        setIsOnline(true);
        setHasLoadedFromFirestore(true);
        // Note: isRemoteUpdateRef is reset in the auto-sync useEffect
      } else {
        // Document doesn't exist yet, but we are "loaded" (new state)
        setHasLoadedFromFirestore(true);
      }
    }, (error) => {
      onFirestoreError(error, OperationType.GET, path);
      if (error.message.includes('offline')) setIsOnline(false);
    });

    return () => unsub();
  }, [user, isPatronMode]);

  // Force login modal if not logged in and employees exist
  useEffect(() => {
    if (employees.length > 0 && !currentEmployee && !showLoginModal) {
      setShowLoginModal(true);
    }
  }, [employees, currentEmployee, showLoginModal]);

  // Prefill active employee for login if Firebase user matches email
  useEffect(() => {
    if (user && employees.length > 0 && !currentEmployee && !activeEmployeeForLogin) {
      const match = employees.find(e => e.email === user.email);
      if (match) {
        setActiveEmployeeForLogin(match);
      }
    }
  }, [user, employees, currentEmployee, activeEmployeeForLogin]);

  // Update till form name when employee changes
  useEffect(() => {
    if (currentEmployee) {
      setTillForm(prev => ({ ...prev, init: currentEmployee.name }));
    }
  }, [currentEmployee]);

  // Automatic POS Synchronization
  useEffect(() => {
    if (posConfig.provider === 'none' || (!posConfig.autoSyncInventory && !posConfig.autoSyncSales)) return;

    // Small delay to ensure server is ready if app just reloaded
    const timer = setTimeout(() => {
      syncFromPos(true);
    }, 3000);

    // Set up hourly sync
    const interval = setInterval(() => {
      syncFromPos(true);
    }, 60 * 60 * 1000); // 1 hour

    return () => {
      clearTimeout(timer);
      clearInterval(interval);
    };
  }, [posConfig.provider, posConfig.autoSyncInventory, posConfig.autoSyncSales]);

  const requireStaffAuth = (permission?: Permission) => {
    if (employees.length === 0) return true;
    if (!currentEmployee) {
      setShowLoginModal(true);
      addNotification("Access Denied: Staff PIN required", "alert");
      return false;
    }
    
    if (permission && !can(permission)) {
      addNotification(`Insufficient Permissions: ${permission.split('_').join(' ')} required`, "alert");
      return false;
    }

    return true;
  };

  const syncToCloud = async () => {
    if (quotaExceeded) return;
    if (isSyncingRef.current) {
      syncNeededRef.current = true;
      return;
    }
    
    if (!user) {
      try {
        await signIn();
      } catch (e) {
        console.error("Sign in failed", e);
      }
      return;
    }

    isSyncingRef.current = true;
    setIsSyncing(true);
    syncNeededRef.current = false;
    const path = 'system/state';
    try {
      const state = getAppState();
      const cleanState = sanitizeForFirestore(state);
      const stateString = JSON.stringify(cleanState);
      
      // Safety check for Firestore 1MB limit (approx)
      if (stateString.length > 1000000) {
        setIsSyncing(false);
        isSyncingRef.current = false;
        addNotification("Application state is too large (>1MB). Syncing disabled to prevent data loss.", "alert");
        return;
      }

      if (stateString === lastSyncHashRef.current) {
        setIsSyncing(false);
        isSyncingRef.current = false;
        isPendingSyncRef.current = false;
        return;
      }

      // Cloud sync with stringified payload
      await setDoc(doc(db, path), {
        payload: stateString,
        updatedAt: new Date().toISOString(),
        version: 2
      });
      
      lastSyncHashRef.current = stateString;
      setLastSync(new Date().toLocaleTimeString());
    } catch (error) {
      onFirestoreError(error, OperationType.WRITE, path);
    } finally {
      setIsSyncing(false);
      isSyncingRef.current = false;
      isPendingSyncRef.current = false;
      
      // If a change happened while we were syncing, trigger another sync
      // Use the ref to ensure we call the LATEST version of the function (with latest state)
      if (syncNeededRef.current) {
        setTimeout(() => syncToCloudRef.current(), 1000);
      }
    }
  };
  
  // Update the ref every render so it always points to the version with latest state
  useEffect(() => {
    syncToCloudRef.current = syncToCloud;
  });

  // Test connection on boot
  useEffect(() => {
    const testConnection = async () => {
      try {
        await getDocFromServer(doc(db, 'system', 'state'));
        setIsOnline(true);
      } catch (error) {
        if (error instanceof Error && error.message.includes('offline')) {
          setIsOnline(false);
        }
      }
    };
    testConnection();
  }, []);

  // Auto-sync useEffect
  useEffect(() => {
    // If this update was triggered by a remote sync, we don't treat it as "pending local change"
    if (isRemoteUpdateRef.current) {
      isRemoteUpdateRef.current = false;
      return;
    }
    
    // Always mark that a local change happened, regardless of quota
    lastLocalUpdateRef.current = Date.now();

    if (!user || !hasLoadedFromFirestore || quotaExceeded) return;
    
    isPendingSyncRef.current = true;
    const timeoutId = setTimeout(() => {
      syncToCloud();
    }, 3000); // 3s debounce to save Firestore quota

    return () => clearTimeout(timeoutId);
  }, [tasks, checks, inventory, stock, posStock, tills, gaming, invLogs, taskLogs, staffLogs, orderLogs, helpContent, distMetadata, employees, recipes, notifications, undepositedTotal, messages, calendarEvents, user, posConfig, lastPosSync, categoryColors, posLogs, pinResetRequests, pricingConfig, priceAdjustmentPercent, brandingConfig, randomTasksConfig, defaultReminderOffset, commonTitles, commonLocations, scannedInvoices]);

  // Keyboard Shortcuts for Navigation
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.ctrlKey || e.metaKey) && !isNaN(Number(e.key))) {
        const num = parseInt(e.key);
        const tabs: TabId[] = ['dashboard', 'opening', 'closing', 'checks', 'inventory', 'tills', 'gaming', 'staff' as any, 'admin' as any];
        if (num >= 1 && num <= tabs.length) {
          e.preventDefault();
          setCurTab(tabs[num - 1]);
          addNotification(`Navigated to ${tabs[num - 1].toUpperCase()}`, 'info');
        }
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, []);

  // Sync with localStorage - debounced to improve performance
  const saveToLocalStorage = () => {
    localStorage.setItem('se_tasks', JSON.stringify(tasks));
    localStorage.setItem('se_checks', JSON.stringify(checks));
    localStorage.setItem('se_stock', JSON.stringify(stock));
    localStorage.setItem('se_pos_stock', JSON.stringify(posStock));
    localStorage.setItem('se_inv_schema', JSON.stringify(inventory));
    localStorage.setItem('se_tills', JSON.stringify(tills));
    localStorage.setItem('se_gaming', JSON.stringify(gaming));
    localStorage.setItem('se_logs', JSON.stringify(invLogs));
    localStorage.setItem('se_task_logs', JSON.stringify(taskLogs));
    localStorage.setItem('se_staff_logs', JSON.stringify(staffLogs));
    localStorage.setItem('se_order_logs', JSON.stringify(orderLogs));
    localStorage.setItem('se_pricing_config', JSON.stringify(pricingConfig));
    localStorage.setItem('se_price_adjustment_percent', priceAdjustmentPercent.toString());
    localStorage.setItem('se_branding_config', JSON.stringify(brandingConfig));
    localStorage.setItem('se_random_tasks_config', JSON.stringify(randomTasksConfig));
    localStorage.setItem('se_help_content', helpContent);
    localStorage.setItem('se_dist_metadata', JSON.stringify(distMetadata));
    localStorage.setItem('se_employees', JSON.stringify(employees));
    localStorage.setItem('se_recipes', JSON.stringify(recipes));
    localStorage.setItem('se_food_menu', JSON.stringify(foodMenu));
    localStorage.setItem('se_notifications', JSON.stringify(notifications));
    localStorage.setItem('se_undeposited_total', undepositedTotal.toString());
    localStorage.setItem('se_messages', JSON.stringify(messages));
    localStorage.setItem('se_calendar_events', JSON.stringify(calendarEvents));
    localStorage.setItem('se_common_titles', JSON.stringify(commonTitles));
    localStorage.setItem('se_common_locations', JSON.stringify(commonLocations));
    localStorage.setItem('se_category_colors', JSON.stringify(categoryColors));
    localStorage.setItem('se_pos_config', JSON.stringify(posConfig));
    localStorage.setItem('se_specials', JSON.stringify(specials));
    if (lastPosSync) localStorage.setItem('se_last_pos_sync', lastPosSync);
    localStorage.setItem('se_pos_logs', JSON.stringify(posLogs));
    localStorage.setItem('se_pin_reset_requests', JSON.stringify(pinResetRequests));
    localStorage.setItem('se_last_local_update', new Date().toISOString());
  };

  useEffect(() => {
    const timeoutId = setTimeout(saveToLocalStorage, 500);
    return () => clearTimeout(timeoutId);
  }, [tasks, checks, stock, inventory, posStock, tills, gaming, invLogs, taskLogs, staffLogs, orderLogs, helpContent, distMetadata, employees, recipes, foodMenu, notifications, undepositedTotal, messages, calendarEvents, commonTitles, commonLocations, categoryColors, posConfig, lastPosSync, posLogs, pinResetRequests, pricingConfig, priceAdjustmentPercent, brandingConfig, randomTasksConfig, specials]);

  // Flush sync on visibility change or before unload
  useEffect(() => {
    const flushSync = () => {
      saveToLocalStorage();
      if (isPendingSyncRef.current && user && hasLoadedFromFirestore && !quotaExceeded) {
        syncToCloud();
      }
    };

    const handleVisibilityChange = () => {
      if (document.visibilityState === 'hidden') {
        flushSync();
      }
    };

    window.addEventListener('visibilitychange', handleVisibilityChange);
    window.addEventListener('beforeunload', flushSync);

    return () => {
      window.removeEventListener('visibilitychange', handleVisibilityChange);
      window.removeEventListener('beforeunload', flushSync);
    };
  }, [tasks, checks, stock, inventory, posStock, tills, gaming, invLogs, taskLogs, staffLogs, orderLogs, helpContent, distMetadata, employees, recipes, notifications, undepositedTotal, messages, calendarEvents, user, posConfig, lastPosSync, categoryColors, posLogs, pinResetRequests, pricingConfig, hasLoadedFromFirestore, quotaExceeded]);


  useEffect(() => {
    const refreshSmtpStatus = async () => {
      try {
        const res = await fetch('/api/smtp-status');
        if (res.ok) {
          const data = await res.json();
          setSmtpStatus(data);
        }
      } catch (err) {
        console.error("Failed to fetch SMTP status", err);
      }
    };
    refreshSmtpStatus();
  }, []);

  // Shift Reminders Effect - Checks every 5 minutes
  useEffect(() => {
    const checkReminders = async () => {
      if (calendarEvents.length === 0 || employees.length === 0) return;

      const now = new Date();
      const oneHourFromNow = new Date(now.getTime() + 60 * 60 * 1000);
      
      const shiftsToRemind = calendarEvents.filter(event => {
        if (event.type !== 'shift' || event.reminderSent) return false;
        const shiftStart = new Date(event.start);
        // Only if it starts within the next hour AND hasn't started yet
        return shiftStart > now && shiftStart <= oneHourFromNow;
      });

      if (shiftsToRemind.length === 0) return;

      let updatedEvents = false;
      const newCalendarEvents = [...calendarEvents];

      for (const shift of shiftsToRemind) {
        // Send reminders to all assigned employees
        if (shift.assignedTo && shift.assignedTo.length > 0) {
          for (const name of shift.assignedTo) {
            const emp = employees.find(e => e.name === name);
            if (emp?.email) {
              try {
                const res = await fetch('/api/send-shift-notification', {
                  method: 'POST',
                  headers: { 'Content-Type': 'application/json' },
                  body: JSON.stringify({
                    email: emp.email,
                    employeeName: emp.name,
                    shiftTitle: shift.title,
                    shiftStart: shift.start,
                    type: 'reminder'
                  })
                });
                if (res.ok) {
                  addNotification(`Shift reminder sent to ${emp.name}`, "info");
                }
              } catch (err) {
                console.error(`Failed to send reminder to ${emp.name}`, err);
              }
            }
          }
          
          // Mark as sent
          const idx = newCalendarEvents.findIndex(e => e.id === shift.id);
          if (idx !== -1) {
            newCalendarEvents[idx] = { ...newCalendarEvents[idx], reminderSent: true };
            updatedEvents = true;
          }
        }
      }

      if (updatedEvents) {
        setCalendarEvents(newCalendarEvents);
      }
    };

    const interval = setInterval(checkReminders, 5 * 60 * 1000); // Check every 5 minutes
    // Initial check after a short delay to allow data sync
    const initialTimeout = setTimeout(checkReminders, 10000); 

    return () => {
      clearInterval(interval);
      clearTimeout(initialTimeout);
    };
  }, [calendarEvents, employees]);

  // Inventory Reminder Effect
  useEffect(() => {
    if (!distMetadata) return;
    const days = ["Sunday", "Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday"];
    const today = new Date().getDay();
    const tomorrowName = days[(today + 1) % 7];
    
    Object.entries(distMetadata).forEach(([dist, meta]) => {
      if (meta.orderDay === tomorrowName) {
        const msg = `📋 REMINDER: Inventory for ${dist} should be completed today (Order day is tomorrow, ${tomorrowName}).`;
        // Check if we already have this notification today
        const alreadyNotified = notifications.some(n => 
          n.m.includes(`Inventory for ${dist} should be completed today`) && 
          new Date(n.ts).toDateString() === new Date().toDateString()
        );
        if (!alreadyNotified) {
          addNotification(msg, 'task', true, 'employee');
        }
      }
    });
  }, [distMetadata, notifications]);

  // Auto-fill gaming prev total
  useEffect(() => {
    if (curTab === 'gaming' && gaming.length > 0) {
      const last = gaming[0];
      const prevVal = (Number(last.p) + Number(last.tk) - Number(last.d)).toFixed(2);
      setGamingForm(prev => ({ ...prev, prev: prevVal }));
    }
  }, [curTab, gaming]);

  const sendOrder = (distributor: string, items: any[], mode: 'email' | 'sms') => {
    if (!requireStaffAuth()) return;
    const meta = distMetadata[distributor];
    
    // Check for missing details
    const missingDetails = [];
    if (!meta?.repName) missingDetails.push('Contact Name (Rep Name)');
    if (mode === 'email' && !meta?.email) missingDetails.push('Email');
    if (mode === 'sms' && !meta?.phone) missingDetails.push('Phone');
    if (!meta?.paymentTerms) missingDetails.push('Payment Terms');
    if (!meta?.deliverySchedule) missingDetails.push('Delivery Schedule');

    if (missingDetails.length > 0) {
      if (confirm(`The following details are missing for ${distributor}:\n- ${missingDetails.join('\n- ')}\n\nWould you like to go to the Distributors tab to add them?`)) {
        setCurTab('distributors');
      }
      return;
    }

    const availableItems = items.filter(o => !o.item.oos);
    if (availableItems.length === 0) {
      addNotification("No available items to order (all selected items are currently out of stock at distributor)", "alert");
      return;
    }

    const orderLines = availableItems.map(o => `- ${o.item.n}: ${o.order} ${o.item.u || 'item'}(s) (On Hand: ${o.current})`).join('\n');
    const intro = meta?.repName ? `Hi ${meta.repName},\n\n` : '';
    
    const termsInfo = `Payment Terms: ${meta.paymentTerms || 'Not specified'}\n`;
    const scheduleInfo = `Delivery Schedule: ${meta.deliverySchedule || 'Not specified'}\n`;
    
    const body = `${intro}Please fulfill the following order for Smoke Eaters:\n\n${orderLines}\n\n${termsInfo}${scheduleInfo}\nThanks,\n${currentEmployee?.name || 'Staff'}`;

    const recordOrder = (method: 'email' | 'sms') => {
      const log: OrderLogEntry = {
        t: new Date().toISOString(),
        d: distributor,
        i: items.map(o => ({ name: o.item.n, amount: o.order, unit: o.item.u })),
        m: method,
        e: currentEmployee?.name || 'Staff'
      };
      setOrderLogs(prev => [log, ...(prev || [])].slice(0, 100));
    };

    if (mode === 'email') {
      const subject = `Smoke Eaters Order - ${distributor}`;
      window.open(`mailto:${meta.email}?subject=${encodeURIComponent(subject)}&body=${encodeURIComponent(body)}`);
      addNotification(`Drafting email to ${distributor}`, 'success');
      recordOrder('email');
    } else {
      // Copy to clipboard first for convenience
      navigator.clipboard.writeText(body).then(() => {
        const smsLink = `sms:${meta.phone}${window.navigator.userAgent.match(/iPhone/i) ? '&' : '?'}body=${encodeURIComponent(body)}`;
        window.open(smsLink);
        addNotification(`Order copied & opening text for ${distributor}`, 'success');
        recordOrder('sms');
      }).catch(() => {
        const smsLink = `sms:${meta.phone}${window.navigator.userAgent.match(/iPhone/i) ? '&' : '?'}body=${encodeURIComponent(body)}`;
        window.open(smsLink);
        addNotification(`Opening text for ${distributor}`, 'success');
        recordOrder('sms');
      });
    }
  };

  const addEmployee = () => {
    if (!requireStaffAuth()) return;
    if (!newEmployee.name) return;
    if (newEmployee.role !== 'support' && !newEmployee.pin) {
      addNotification("PIN required for standard roles", "alert");
      return;
    }

    // Uniqueness check for PIN
    if (newEmployee.role !== 'support' && employees.some(e => e.pin === newEmployee.pin)) {
      addNotification("This PIN is already assigned to another staff member", "alert");
      return;
    }
    
    // Safety check: Only admins can assign roles (if any employees exist)
    if (employees.length > 0 && !can('manage_employees')) {
      addNotification("Unauthorized: Only admins can manage staff roles", "alert");
      return;
    }

    // Auto-promote first employee to admin if no staff exists
    const roleToAssign: EmployeeRole = employees.length === 0 ? 'admin' : newEmployee.role;
    
    const emp: Employee = {
      id: Date.now().toString(),
      name: newEmployee.name,
      pin: newEmployee.role === 'support' ? undefined : newEmployee.pin,
      role: roleToAssign,
      email: newEmployee.email,
      phone: newEmployee.phone,
      hireDate: newEmployee.hireDate,
      allowedTabs: newEmployee.allowedTabs,
      customFields: newEmployee.customFields || {}
    };
    setEmployees(prev => [...prev, emp]);
    setNewEmployee({ 
      name: '', 
      pin: '', 
      role: 'employee', 
      email: '', 
      phone: '', 
      hireDate: new Date().toISOString().split('T')[0],
      allowedTabs: ['dashboard', 'opening', 'closing', 'inventory', 'instructions', 'notifications', 'calendar', 'messages'],
      customFields: {}
    });
    if (employees.length === 0) {
      addNotification(`First admin created: ${emp.name}`, 'success');
    } else {
      addNotification(`Staff member ${emp.name} added`, 'success');
    }
  };

  const updateEmployee = (updated: Employee) => {
    // Uniqueness check for PIN
    if (updated.pin && employees.some(e => e.pin === updated.pin && e.id !== updated.id)) {
      addNotification("This PIN is already assigned to another staff member", "alert");
      return;
    }

    setEmployees(prev => prev.map(emp => emp.id === updated.id ? updated : emp));
    
    // Clear any pending PIN reset requests for this employee
    setPinResetRequests(prev => prev.map(p => 
      p.employeeId === updated.id ? { ...p, status: 'resolved' as const } : p
    ));

    if (currentEmployee?.id === updated.id) {
      setCurrentEmployee(updated);
    }
    addNotification(`Staff member ${updated.name} updated`, 'info');
    setEditingEmployee(null);
  };

