  const completeEmployeeLogin = (employee: Employee) => {
    setCurrentEmployee(employee);
    setCurTab('dashboard');
    setLastActivity(Date.now());
    setLoginPin('');
    setActiveEmployeeForLogin(null);
    setShowLoginModal(false);
    
    const log: StaffLogEntry = {
      t: new Date().toISOString(),
      e: employee.name,
      a: 'login'
    };
    setStaffLogs(prev => [log, ...prev].slice(0, 200));

    // Handle shift weekly task assignment!
    if (randomTasksConfig.shiftRandomizationEnabled) {
      const todayStr = new Date().toISOString().split('T')[0];
      const hasAssignmentToday = (randomTasksConfig.assignments || []).some(
        a => a.employeeId === employee.id && a.date === todayStr
      );

      if (!hasAssignmentToday) {
        const roll = Math.random() * 100;
        const targetChance = randomTasksConfig.shiftAssignmentChance !== undefined ? randomTasksConfig.shiftAssignmentChance : 100;
        if (roll <= targetChance) {
          const currentHour = new Date().getHours();
          const shift: 'opening' | 'closing' = currentHour < 16 ? 'opening' : 'closing';
          
          const shiftTasks = tasks[shift] || [];
          const weeklyTasks = shiftTasks.filter(t => t.f === 'weekly');

          if (weeklyTasks.length > 0) {
            const randomIndex = Math.floor(Math.random() * weeklyTasks.length);
            const selectedTask = weeklyTasks[randomIndex];

            const newAssignment: AssignedShiftTask = {
              id: Math.random().toString(36).substr(2, 9),
              employeeId: employee.id,
              employeeName: employee.name,
              shift,
              taskName: selectedTask.n,
              f: 'weekly',
              date: todayStr,
              completed: false
            };

            setRandomTasksConfig(prev => ({
              ...prev,
              assignments: [newAssignment, ...(prev.assignments || [])]
            }));

            // Immediately trigger a persistent toast/alert pop-up
            addNotification(`⚠️ MINUTE TASK ASSIGNED: Choose tab checklist and do task "${selectedTask.n}".`, 'alert', true, undefined, employee.id);
          }
        }
      }
    }
  };

