  const handleAddSpecial = () => {
    if (!specialItemName) {
      addNotification("Please select an item to set as a special!", "alert");
      return;
    }

    // Retrieve original price to perform validation
    let originalPrice = 0;
    if (specialItemType === 'food') {
      const found = foodMenu.find(f => f.name === specialItemName);
      if (found) originalPrice = found.price;
    } else {
      const found = recipes.find(r => r.name === specialItemName);
      if (found) {
        if (found.sellingPrice !== undefined && found.sellingPrice > 0) {
          originalPrice = found.sellingPrice;
        } else {
          originalPrice = 8.50; // Fallback rate
        }
      }
    }

    if (originalPrice <= 0) {
      addNotification("Could not resolve item original price", "alert");
      return;
    }

    let calculatedDiscount = 0;
    if (specialDiscountType === 'percentage') {
      calculatedDiscount = originalPrice * (specialDiscountValue / 100);
    } else {
      calculatedDiscount = specialDiscountValue;
    }

    // Apply strict validation guards
    if (specialItemType === 'food') {
      const fiftyPercentLimit = originalPrice * 0.5;
      if (calculatedDiscount > fiftyPercentLimit) {
        addNotification(`Maximum discount for food item "${specialItemName}" is 50% off ($${fiftyPercentLimit.toFixed(2)}). The discount is capped at 50%.`, "info");
        calculatedDiscount = fiftyPercentLimit;
      }
    } else {
      if (calculatedDiscount > 1.00) {
        addNotification(`Maximum discount for drink recipe "${specialItemName}" is $1.00. Capped at $1.00 off.`, "info");
        calculatedDiscount = 1.00;
      }
    }

    // Deduce final value to write
    let finalDiscountValue = specialDiscountValue;
    if (specialDiscountType === 'percentage') {
      finalDiscountValue = Math.round((calculatedDiscount / originalPrice) * 100);
    } else {
      finalDiscountValue = Number(Number(calculatedDiscount).toFixed(2));
    }

    const specialsList = specials || [];
    const filteredSpecials = specialsList.filter(s => s.name.toLowerCase() !== specialItemName.toLowerCase());

    const newSpecial: Special = {
      id: `spec-${Date.now()}`,
      name: specialItemName,
      type: specialItemType,
      discountType: specialDiscountType,
      discountValue: finalDiscountValue,
      period: specialPeriod
    };

    const nextSpecials = [...filteredSpecials, newSpecial];
    setSpecials(nextSpecials);
    addNotification(`Added special for ${specialItemName} (${specialPeriod})`, 'success');

    // Reset fields
    setSpecialItemName('');
    setSpecialDiscountValue(0);
  };

  const handleRemoveSpecial = (id: string) => {
    const nextSpecials = (specials || []).filter(s => s.id !== id);
    setSpecials(nextSpecials);
    addNotification("Removed special successfully", "info");
  };

