  const downloadRecipesTxt = () => {
    if (recipes.length === 0) {
      addNotification("No recipes found to download.", "alert");
      return;
    }

    const titleBlock = [
      "==================================================",
      "             THE MASTER DRINK BIBLE               ",
      `             Generated on ${new Date().toLocaleDateString()}           `,
      "==================================================",
      `Total Recipes: ${recipes.length}`,
      "",
    ].join("\n");

    const grouped: Record<string, Recipe[]> = {};
    recipes.forEach(r => {
      const cat = r.category || 'Other';
      if (!grouped[cat]) grouped[cat] = [];
      grouped[cat].push(r);
    });

    let body = titleBlock;

    Object.keys(grouped).sort().forEach(cat => {
      body += `\n\n=== ${cat.toUpperCase()} ===\n`;
      body += "=".repeat(cat.length + 8) + "\n\n";

      grouped[cat].forEach(r => {
        const costVal = calculateRecipeCost(r);
        const sellPrice = r.sellingPrice !== undefined ? r.sellingPrice : 10;
        const cogs = sellPrice > 0 ? (costVal / sellPrice) * 100 : 0;
        const glass = r.glassware || 'Standard Glass';
        const method = r.method || 'Built';
        const garnish = r.garnish || 'None';

        body += `🍹 ${r.name.toUpperCase()}\n`;
        body += `   Category:      ${r.category}\n`;
        body += `   Glassware:     ${glass}\n`;
        body += `   Method:        ${method}\n`;
        body += `   Garnish:       ${garnish}\n`;
        body += `   Est. Cost:     $${costVal.toFixed(2)}\n`;
        body += `   Retail Price:  $${sellPrice.toFixed(2)}\n`;
        body += `   Pour Cost:     ${cogs.toFixed(1)}%\n\n`;
        body += `   INGREDIENTS:\n`;
        r.ingredients.forEach(i => {
          body += `     • ${i.item}: ${i.amount}\n`;
        });
        body += `\n   INSTRUCTIONS:\n`;
        body += `     ${r.instructions}\n`;
        if (r.barNotes) {
          body += `\n   BAR NOTES:\n`;
          body += `     ${r.barNotes}\n`;
        }
        if (r.insight) {
          body += `\n   BOH INSIGHT:\n`;
          body += `     "${r.insight}"\n`;
        }
        body += `\n${"-".repeat(40)}\n\n`;
      });
    });

    const blob = new Blob([body], { type: 'text/plain;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.setAttribute("download", "bar_recipe_bible.txt");
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
    addNotification("Drink Bible text file downloaded successfully!", "success");
  };

  const downloadRecipesCsv = () => {
    if (recipes.length === 0) {
      addNotification("No recipes found to download.", "alert");
      return;
    }

    const headers = ["ID", "Name", "Category", "Glassware", "Method", "Garnish", "Est Cost ($)", "Retail Price ($)", "Pour Cost COGS (%)", "Ingredients", "Instructions", "Bar Notes", "BOH Insight"];
    const rows = recipes.map(r => {
      const costVal = calculateRecipeCost(r);
      const sellPrice = r.sellingPrice !== undefined ? r.sellingPrice : 10;
      const cogs = sellPrice > 0 ? ((costVal / sellPrice) * 100).toFixed(1) : "0";
      const glass = r.glassware || 'Standard';
      const method = r.method || 'Built';
      const garnish = r.garnish || 'None';
      const ingredientsCsv = r.ingredients.map(i => `${i.item} (${i.amount})`).join("; ");
      const quote = (str: string) => `"${str.replace(/"/g, '""').replace(/\n/g, ' ')}"`;

      return [
        quote(r.id),
        quote(r.name),
        quote(r.category),
        quote(glass),
        quote(method),
        quote(garnish),
        costVal.toFixed(2),
        sellPrice.toFixed(2),
        cogs,
        quote(ingredientsCsv),
        quote(r.instructions),
        quote(r.barNotes || ""),
        quote(r.insight || "")
      ];
    });

    const csvContent = [headers.join(","), ...rows.map(line => line.join(","))].join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.setAttribute("download", "bar_recipes_export.csv");
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
    addNotification("Recipes CSV exported successfully!", "success");
  };

