  const editTill = (idx: number, field: keyof TillLog, val: string) => {
    if (!requireStaffAuth()) return;
    setTills(prev => {
      const newTills = [...prev];
      const entry = { ...newTills[idx] };
      if (field === 'd') {
        entry.d = parseFloat(val) || 0;
        // Recalculate diff if deposit or receipts (not stored but implied) changed
        // Since we don't store receipts in the log, we can't perfectly recalculate df 
        // unless we store it. Let's just allow editing df directly or keep it as is.
      } else if (field === 'm' || field === 'i' || field === 'df' || field === 'date') {
        (entry as any)[field] = val;
      } else if (field === 'ba') {
        entry.ba = val as any === true;
      }
      newTills[idx] = entry;
      return newTills;
    });
  };

  const delGaming = (idx: number) => {
    if (!requireStaffAuth()) return;
    setConfirmConfig({
      show: true,
      title: 'Delete Entry',
      message: 'Are you sure you want to delete this gaming entry?',
      type: 'danger',
      onConfirm: () => {
        setGaming(prev => {
          const newGaming = [...prev];
          newGaming.splice(idx, 1);
          return newGaming;
        });
        setConfirmConfig(p => ({ ...p, show: false }));
      }
    });
  };

  const editGaming = (idx: number, field: keyof GamingLog, val: string) => {
    if (!requireStaffAuth()) return;
    setGaming(prev => {
      const newGaming = [...prev];
      const entry = { ...newGaming[idx] };
      (entry as any)[field] = parseFloat(val) || 0;
      
      // Recalculate total
      const ctg = entry.ctg;
      const g = entry.g;
      const d = entry.d;
      const p = entry.p;
      const tk = entry.tk;
      entry.tt = (ctg + g + p + tk - d).toFixed(2);
      
      newGaming[idx] = entry;
      return newGaming;
    });
  };

  const addItem = () => {
    if (!requireStaffAuth()) return;
    
    const errors: { [key: string]: string } = {};
    if (!newItem.d) errors.d = "Distributor is required";
    if (!newItem.n.trim()) errors.n = "Item name is required";
    
    // Validate cost field
    if (newItem.c !== '') {
      const parsedCost = parseFloat(newItem.c);
      if (isNaN(parsedCost)) {
        errors.c = "Cost must be a valid number";
      } else if (parsedCost < 0) {
        errors.c = "Cost cannot be negative";
      }
    }
    
    // Validate stock field
    if (newItem.s !== '') {
      const parsedStock = parseFloat(newItem.s);
      if (isNaN(parsedStock)) {
        errors.s = "Initial stock must be a valid number";
      } else if (parsedStock < 0) {
        errors.s = "Initial stock cannot be negative";
      }
    }

    // Validate minimum stock
    if (newItem.m !== '') {
      const parsedMin = parseInt(newItem.m);
      if (isNaN(parsedMin)) {
         errors.m = "Minimum stock must be a valid integer";
      } else if (parsedMin < 0) {
         errors.m = "Minimum stock cannot be negative";
      }
    }

    // Validate par level
    if (newItem.p !== '') {
      const parsedPar = parseInt(newItem.p);
      const parsedMin = parseInt(newItem.m) || 0;
      if (isNaN(parsedPar)) {
        errors.p = "Par level must be a valid integer";
      } else if (parsedPar < 0) {
        errors.p = "Par level cannot be negative";
      } else if (parsedPar < parsedMin) {
        errors.p = `Par level (${parsedPar}) should be greater than or equal to Minimum Stock (${parsedMin})`;
      }
    }

    if (Object.keys(errors).length > 0) {
      setNewItemErrors(errors);
      return;
    }

    setNewItemErrors({});

    if (newItem.d && newItem.n) {
      setInventory(prev => {
        const newInv = { ...prev };
        if (!newInv[newItem.d]) newInv[newItem.d] = [];
        
        const existingIdx = newInv[newItem.d].findIndex(it => it.n.toLowerCase() === newItem.n.toLowerCase());
        const updatedItem = { 
          n: newItem.n, 
          m: parseInt(newItem.m) || 0, 
          p: newItem.p ? parseInt(newItem.p) : undefined,
          u: newItem.u,
          sz: newItem.sz,
          c: newItem.c ? parseFloat(newItem.c) : undefined,
          isMixer: !!newItem.isMixer,
          isFood: !!newItem.isFood,
          portionCount: newItem.isFood && newItem.portionCount ? parseInt(newItem.portionCount) : undefined,
          overridePrice: newItem.overridePrice ? parseFloat(newItem.overridePrice) : undefined
        };

        if (existingIdx >= 0) {
          newInv[newItem.d][existingIdx] = { ...newInv[newItem.d][existingIdx], ...updatedItem };
        } else {
          newInv[newItem.d].push(updatedItem);
        }
        return newInv;
      });

      if (newItem.s) {
        const stockVal = parseFloat(newItem.s) || 0;
        setStock(prev => ({ ...prev, [newItem.n]: stockVal }));
        setInvLogs(prev => [
          { t: new Date().toISOString(), i: newItem.n, a: 'ADD', f: stockVal, u: currentEmployee?.name || 'System' },
          ...prev.slice(0, 49)
        ]);
      }

      setNewItem({ d: '', n: '', m: '', u: 'item', c: '', p: '', sz: '', s: '', isMixer: false, isFood: false, portionCount: '1', overridePrice: '' });
      setShowAddModal(null);
    }
  };

  const processBulkImport = () => {
    if (!requireStaffAuth()) return;
    if (!bulkDist || !bulkData.trim()) return;

    const rows = bulkData.split('\n').filter(r => r.trim());
    const warnings: string[] = [];
    const processedItems: { item: InventoryItem; stock?: number }[] = [];

    rows.forEach((row, index) => {
      const parts = row.split(',').map(p => p.trim());
      // format: Name, Min, Unit, Cost (optional), Par (optional), Stock (optional)
      const n = parts[0];
      if (!n) {
        warnings.push(`Row ${index + 1}: Skipped due to missing item name.`);
        return;
      }

      const m = parseInt(parts[1]);
      if (isNaN(m) || m < 0) {
        warnings.push(`Row ${index + 1} (${n}): Invalid minimum stock level. Defaulting to 1.`);
      }
      const finalMin = isNaN(m) || m < 0 ? 1 : m;

      const u = parts[2] || 'item';

      let c: number | undefined = undefined;
      if (parts[3] !== undefined && parts[3] !== '') {
        const parsedCost = parseFloat(parts[3]);
        if (isNaN(parsedCost) || parsedCost < 0) {
          warnings.push(`Row ${index + 1} (${n}): Cost "${parts[3]}" is invalid. Cost omitted.`);
        } else {
          c = parsedCost;
        }
      }

      let p: number | undefined = undefined;
      if (parts[4] !== undefined && parts[4] !== '') {
        const parsedPar = parseInt(parts[4]);
        if (isNaN(parsedPar) || parsedPar < 0) {
          warnings.push(`Row ${index + 1} (${n}): Par level "${parts[4]}" is invalid. Par level omitted.`);
        } else if (parsedPar < finalMin) {
          warnings.push(`Row ${index + 1} (${n}): Par level (${parsedPar}) is less than Min (${finalMin}). Corrected to par limit.`);
          p = finalMin;
        } else {
          p = parsedPar;
        }
      }

      let s: number | undefined = undefined;
      if (parts[5] !== undefined && parts[5] !== '') {
        const parsedStock = parseFloat(parts[5]);
        if (isNaN(parsedStock) || parsedStock < 0) {
          warnings.push(`Row ${index + 1} (${n}): Stock position "${parts[5]}" is invalid. Stock level omitted.`);
        } else {
          s = parsedStock;
        }
      }

      processedItems.push({
        item: { n, m: finalMin, u, c, p },
        stock: s
      });
    });

    if (warnings.length > 0) {
      setBulkImportWarnings(warnings);
      // Keep modal open so operator can view logs, but commit the validated items!
    } else {
      setBulkImportWarnings([]);
      setShowAddModal(null);
    }

    if (processedItems.length > 0) {
      setInventory(prev => {
        const newInv = { ...prev };
        if (!newInv[bulkDist]) newInv[bulkDist] = [];
        const updatedList = [...newInv[bulkDist]];
        
        processedItems.forEach(({ item: ni }) => {
          const idx = updatedList.findIndex(it => it.n.toLowerCase() === ni.n.toLowerCase());
          if (idx >= 0) {
            updatedList[idx] = { ...updatedList[idx], ...ni };
          } else {
            updatedList.push(ni);
          }
        });
        
        newInv[bulkDist] = updatedList;
        return newInv;
      });

      setStock(prev => {
        const next = { ...prev };
        processedItems.forEach(({ item, stock }) => {
          if (stock !== undefined) {
            next[item.n] = stock;
          }
        });
        return next;
      });

      // Log bulk additions to stock
      const now = new Date().toISOString();
      setInvLogs(prev => [
        ...processedItems.filter(pi => pi.stock !== undefined).map(pi => ({
          t: now,
          i: pi.item.n,
          a: 'ADD' as const,
          f: pi.stock!,
          u: currentEmployee?.name || 'System'
        })),
        ...prev
      ].slice(0, 500));

      setBulkData('');
      if (warnings.length === 0) {
        setBulkDist('');
      }
    }
  };

  const processBulkTasks = () => {
    if (!requireStaffAuth()) return;
    if (!bulkData.trim()) return;

    const rows = bulkData.split('\n').filter(r => r.trim());
    const newTasks: Task[] = rows.map(row => {
      const parts = row.split(',').map(p => p.trim());
      // format: Name, Frequency (default daily)
      const n = parts[0] || 'Unknown Task';
      let f: TaskFrequency = 'daily';
      const freqInput = (parts[1] || 'daily').toLowerCase();
      if (freqInput === 'weekly') f = 'weekly';
      else if (freqInput === 'monthly') f = 'monthly';
      
      return { n, f };
    });

    setTasks(prev => ({
      ...prev,
      [bulkTaskShift]: [...prev[bulkTaskShift], ...newTasks]
    }));
    setBulkData('');
    setShowAddModal(null);
  };

  const addDistributor = () => {
    if (!requireStaffAuth()) return;
    if (newDistributor.name.trim()) {
      const name = newDistributor.name.trim();
      setInventory(prev => ({
        ...prev,
        [name]: []
      }));
      setDistMetadata(prev => ({
        ...prev,
        [name]: {
          repName: newDistributor.repName,
          email: newDistributor.email,
          phone: newDistributor.phone,
          paymentTerms: newDistributor.paymentTerms,
          deliverySchedule: newDistributor.deliverySchedule,
          frequency: newDistributor.frequency,
          orderDay: newDistributor.orderDay
        }
      }));
      setNewDistributor({ 
        name: '', 
        repName: '', 
        email: '', 
        phone: '', 
        paymentTerms: '', 
        deliverySchedule: '',
        frequency: 'weekly',
        orderDay: 'Monday'
      });
      setShowAddModal(null);
      addNotification(`Distributor "${name}" added`, 'success');
    }
  };

