    setStock(prev => ({ ...prev, [n]: count }));
    setInvLogs(prev => [
      { t: new Date().toISOString(), i: n, a: 'ADD', f: count, u: currentEmployee?.name || 'System' },
      ...prev.slice(0, 99)
    ]);
