                    className="py-4 bg-transparent border-2 border-orange-500/30 text-orange-400 hover:text-white hover:bg-orange-500/10 hover:border-orange-500/50 rounded-2xl text-xs font-black uppercase tracking-widest transition-all active:scale-[0.98] disabled:opacity-30 disabled:cursor-not-allowed disabled:hover:bg-transparent disabled:hover:text-orange-400 disabled:hover:border-orange-500/30 font-extrabold cursor-pointer"
