                          { label: '🍹 Sage Rita (t1-s1)', code: 'ORDER|id:ord-1|type:cocktail|name:Smoked Sage Rita|table:t1|seat:1|guest:Rhian Hart|price:16.50|notes:no salt' },
                          { label: '🔥 Wings (t2-s3)', code: 'ORDER|id:food-ord-2|type:food|name:Hickory Wings x2|table:t2|seat:3|guest:Jack Brown|price:18.00|notes:extra hot' }
