                                <div className="flex flex-col">
                                  <span className="text-[10px] font-black uppercase text-gray-300">Auto-Sync Inventory</span>
                                  <span className="text-[8px] font-bold text-gray-600 uppercase">Updates stock levels automatically every hour</span>
                                </div>
